#include <cuda_bf16.h>
#include <mma.h>
using namespace nvcuda;

__global__
__launch_bounds__(128) void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int warp_id = threadIdx.x / 32;
    int warp_m = warp_id / 2, warp_n = warp_id % 2;
    int block_m = blockIdx.y * 64, block_n = blockIdx.x * 64;
    int tid = threadIdx.x;
    __shared__ __nv_bfloat16 As[2048];
    __shared__ __nv_bfloat16 Bs[2048];
    wmma::fragment<wmma::accumulator, 16, 16, 16, float> c00, c01, c10, c11;
    wmma::fill_fragment(c00, 0.0f);
    wmma::fill_fragment(c01, 0.0f);
    wmma::fill_fragment(c10, 0.0f);
    wmma::fill_fragment(c11, 0.0f);
    for (int tile_k = 0; tile_k < K; tile_k += 32) {
        #pragma unroll
        for (int p = 0; p < 16; p++) {
            int idx = tid + p * 128;
            int r = idx >> 4, c = idx & 31;
            int gr = block_m + r, gc = tile_k + c;
            As[r * 32 + c] = __float2bfloat16((gr < M && gc < K) ? A[gr * K + gc] : 0.0f);
        }
        #pragma unroll
        for (int p = 0; p < 16; p++) {
            int idx = tid + p * 128;
            int r = idx >> 6, c = idx & 63;
            int gr = tile_k + r, gc = block_n + c;
            Bs[r * 64 + c] = __float2bfloat16((gr < K && gc < N) ? B[gr * N + gc] : 0.0f);
        }
        __syncthreads();
        int wm = warp_m * 32, wn = warp_n * 32;
        wmma::fragment<wmma::matrix_a, 16, 16, 16, __nv_bfloat16, wmma::row_major> af;
        wmma::fragment<wmma::matrix_b, 16, 16, 16, __nv_bfloat16, wmma::row_major> bf;
        #pragma unroll
        for (int wk = 0; wk < 32; wk += 16) {
        wmma::load_matrix_sync(af, &As[(wm+0)*32+wk], 32);
        wmma::load_matrix_sync(bf, &Bs[wk*64+wn+0], 64);
        wmma::mma_sync(c00, af, bf, c00);
        wmma::load_matrix_sync(af, &As[(wm+0)*32+wk], 32);
        wmma::load_matrix_sync(bf, &Bs[wk*64+wn+16], 64);
        wmma::mma_sync(c01, af, bf, c01);
        wmma::load_matrix_sync(af, &As[(wm+16)*32+wk], 32);
        wmma::load_matrix_sync(bf, &Bs[wk*64+wn+0], 64);
        wmma::mma_sync(c10, af, bf, c10);
        wmma::load_matrix_sync(af, &As[(wm+16)*32+wk], 32);
        wmma::load_matrix_sync(bf, &Bs[wk*64+wn+16], 64);
        wmma::mma_sync(c11, af, bf, c11);
        }
        __syncthreads();
    }
    int wm = warp_m * 32, wn = warp_n * 32;
    if (block_m+wm+0+16 <= M && block_n+wn+0+16 <= N)
        wmma::store_matrix_sync(&C[(block_m+wm+0)*N + block_n+wn+0], c00, N, wmma::mem_row_major);
    if (block_m+wm+0+16 <= M && block_n+wn+16+16 <= N)
        wmma::store_matrix_sync(&C[(block_m+wm+0)*N + block_n+wn+16], c01, N, wmma::mem_row_major);
    if (block_m+wm+16+16 <= M && block_n+wn+0+16 <= N)
        wmma::store_matrix_sync(&C[(block_m+wm+16)*N + block_n+wn+0], c10, N, wmma::mem_row_major);
    if (block_m+wm+16+16 <= M && block_n+wn+16+16 <= N)
        wmma::store_matrix_sync(&C[(block_m+wm+16)*N + block_n+wn+16], c11, N, wmma::mem_row_major);
}
